    fn default() -> Self {
        Self::new()
    }
}

impl NextActionId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// A concrete, physical action ready to do. Has a context (required) and
/// an optional project link (projects come in Step 6, so project_id is
/// nullable for now).
///
/// State machine:
///   Active --complete()--> Completed
///
/// Completed actions are removed from the active Next Actions list.
#[derive(Debug, Clone)]
pub enum NextAction {
    Active {
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        title: TodoTitle,
        created_at: DateTime<Utc>,
    },
    Completed {
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: DateTime<Utc>,
    },
}

impl NextAction {
    pub fn new(user_id: UserId, context_id: ContextId, title: TodoTitle) -> Self {
        Self::Active {
            id: NextActionId::new(),
            user_id,
            context_id,
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: Option<DateTime<Utc>>,
    ) -> Self {
        match completed_at {
            Some(completed_at) => Self::Completed {
                id,
                user_id,
                context_id,
                title,
                created_at,
                completed_at,
            },
            None => Self::Active {
                id,
                user_id,
                context_id,
                title,
                created_at,
            },
        }
    }

