        }
    }

    pub fn new_for_project(
        user_id: UserId,
        context_id: ContextId,
        project_id: ProjectId,
        title: TodoTitle,
    ) -> Self {
        Self::Active {
            id: NextActionId::new(),
            user_id,
            context_id,
            project_id: Some(project_id),
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: NextActionId,
        user_id: UserId,
        context_id: ContextId,
        project_id: Option<ProjectId>,
        title: TodoTitle,
        created_at: DateTime<Utc>,
        completed_at: Option<DateTime<Utc>>,
    ) -> Self {
        match completed_at {
            Some(completed_at) => Self::Completed {
                id,
                user_id,
                context_id,
                project_id,
                title,
                created_at,
                completed_at,
            },
