 66→fn build_action_view(action: &NextAction, contexts: &[Context]) -> NextActionView {
 67→    let context_name = contexts
 68→        .iter()
 69→        .find(|c| c.id() == action.context_id())
 70→        .map(|c| c.name().as_str().to_string())
 71→        .unwrap_or_else(|| "Unknown".to_string());
 72→
 73→    NextActionView {
 74→        id: action.id().as_uuid().to_string(),
 75→        title: action.title().as_str().to_string(),
 76→        context_name,
 77→    }
 78→}
