 80→fn build_context_groups(
 81→    actions: &[NextAction],
 82→    contexts: &[Context],
 83→    single_context: bool,
 84→) -> Vec<ContextGroup> {
 85→    if single_context {
 86→        // When filtering by a single context, put all actions in one group
 87→        // (the heading is redundant since the filter pill already shows it)
 88→        let context_name = actions
 89→            .first()
 90→            .and_then(|a| {
 91→                contexts
 92→                    .iter()
 93→                    .find(|c| c.id() == a.context_id())
 94→                    .map(|c| c.name().as_str().to_string())
 95→            })
 96→            .unwrap_or_default();
 97→
 98→        let context_id = actions
 99→            .first()
100→            .map(|a| a.context_id().as_uuid().to_string())
101→            .unwrap_or_default();
102→
103→        let action_views = actions
104→            .iter()
105→            .map(|a| build_action_view(a, contexts))
106→            .collect();
107→
108→        return vec![ContextGroup {
109→            context_name,
110→            context_id,
111→            actions: action_views,
112→        }];
113→    }
114→
115→    // "All" view: group actions by context, preserving context order
116→    let mut groups: Vec<ContextGroup> = Vec::new();
117→
118→    for ctx in contexts {
119→        let ctx_actions: Vec<NextActionView> = actions
120→            .iter()
121→            .filter(|a| a.context_id() == ctx.id())
122→            .map(|a| build_action_view(a, contexts))
123→            .collect();
124→
125→        if !ctx_actions.is_empty() {
126→            groups.push(ContextGroup {
127→                context_name: ctx.name().as_str().to_string(),
128→                context_id: ctx.id().as_uuid().to_string(),
129→                actions: ctx_actions,
130→            });
131→        }
132→    }
133→
134→    groups
135→}
