 995→
 996→  .gtd-nav__link[aria-current="page"] {
 997→    color: var(--color-fg);
 998→    font-weight: var(--font-semibold);
 999→    border-block-end-color: var(--color-primary);
1000→  }
1001→
1002→  /* Inbox count badge -- small pill inside the nav link */
1003→  .gtd-nav__badge {
1004→    display: inline-flex;
1005→    align-items: center;
1006→    justify-content: center;
1007→    min-inline-size: 1.25em;
1008→    padding-inline: 0.4em;
1009→    font-size: var(--font-size-xs);
1010→    font-weight: var(--font-semibold);
1011→    line-height: 1.4;
1012→    background-color: var(--color-primary);
1013→    color: white;
1014→    border-radius: var(--radius-full);
1015→  }
1016→
1017→  @media (prefers-reduced-motion: no-preference) {
1018→    .gtd-nav__link {
1019→      transition: color var(--transition-fast) ease,
1020→                  border-color var(--transition-fast) ease;
1021→    }
1022→  }
1023→
1024→  /* ---- GTD Header Layout ----
1025→   * Wraps the GTD nav + quick capture + logout in the header.
1026→   * Two rows on mobile: nav wraps on top, actions below. */
1027→  .gtd-header {
1028→    display: flex;
1029→    flex-wrap: wrap;
1030→    align-items: center;
1031→    gap: var(--space-sm) var(--space-md);
1032→    padding-block: var(--space-sm);
1033→    border-block-end: 1px solid var(--color-border);
1034→  }
1035→
1036→  .gtd-header__actions {
1037→    display: flex;
1038→    align-items: center;
1039→    gap: var(--space-sm);
1040→    margin-inline-start: auto;
1041→  }
1042→
1043→  /* ---- Quick Capture ----
1044→   * Persistent capture input in the header. Always available
1045→   * on authenticated pages for fast inbox capture. */
1046→  .quick-capture {
1047→    display: flex;
1048→    align-items: center;
1049→    gap: var(--space-xs);
1050→  }
1051→
1052→  .quick-capture__input {
